import base64, os

files = {
    r"src\finanalytics_ai\infrastructure\database\repositories\ohlc_bar_repo.py": "",
    r"tests\unit\application\test_ohlc_handler.py": "",
}

for path, b64 in files.items():
    os.makedirs(os.path.dirname(path) or '.', exist_ok=True)
    with open(path, 'wb') as f:
        f.write(base64.b64decode(b64))
    print(f'Criado: {path}')

print('Concluido!')